create table if not exists employee(id bigint auto_increment primary key,username varchar(32) not null unique,name varchar(32) not null,password varchar(100) not null,phone varchar(20),status int not null default 1,create_time timestamp default current_timestamp);
create table if not exists app_user(id bigint auto_increment primary key,openid varchar(100) not null unique,nickname varchar(50),phone varchar(20),create_time timestamp default current_timestamp);
create table if not exists auth_session(token_hash varchar(64) primary key,subject_id bigint not null,role varchar(16) not null,expires_at timestamp not null,revoked int not null default 0,created_at timestamp default current_timestamp);
create table if not exists category(id bigint auto_increment primary key,type int not null,name varchar(50) not null unique,sort int not null default 0,status int not null default 1,create_time timestamp default current_timestamp,update_time timestamp default current_timestamp);
create table if not exists dish(id bigint auto_increment primary key,category_id bigint not null,name varchar(80) not null unique,price decimal(10,2) not null,image varchar(500),description varchar(500),status int not null default 1,create_time timestamp default current_timestamp,update_time timestamp default current_timestamp,foreign key(category_id) references category(id));
create table if not exists dish_flavor(id bigint auto_increment primary key,dish_id bigint not null,name varchar(50),value varchar(500),foreign key(dish_id) references dish(id) on delete cascade);
create table if not exists setmeal(id bigint auto_increment primary key,category_id bigint not null,name varchar(80) not null unique,price decimal(10,2) not null,image varchar(500),description varchar(500),status int not null default 1,create_time timestamp default current_timestamp,update_time timestamp default current_timestamp,foreign key(category_id) references category(id));
create table if not exists setmeal_dish(id bigint auto_increment primary key,setmeal_id bigint not null,dish_id bigint not null,name varchar(80),price decimal(10,2),copies int default 1,foreign key(setmeal_id) references setmeal(id) on delete cascade,foreign key(dish_id) references dish(id));
create table if not exists address_book(id bigint auto_increment primary key,user_id bigint not null,consignee varchar(50) not null,sex varchar(4),phone varchar(20) not null,province_name varchar(50),city_name varchar(50),district_name varchar(50),detail varchar(200) not null,label varchar(30),is_default int default 0,longitude decimal(10,6),latitude decimal(10,6),foreign key(user_id) references app_user(id));
create table if not exists shopping_cart(id bigint auto_increment primary key,user_id bigint not null,dish_id bigint,setmeal_id bigint,dish_flavor varchar(100),name varchar(80) not null,image varchar(500),amount decimal(10,2) not null,number int not null default 1,create_time timestamp default current_timestamp,foreign key(user_id) references app_user(id));
create table if not exists orders(id bigint auto_increment primary key,number varchar(40) not null unique,user_id bigint not null,address_book_id bigint not null,status int not null default 1,pay_status int not null default 0,pay_method int default 1,amount decimal(10,2) not null,remark varchar(500),phone varchar(20),address varchar(300),consignee varchar(50),order_time timestamp default current_timestamp,checkout_time timestamp,cancel_reason varchar(500),rejection_reason varchar(500),delivery_time timestamp,estimated_delivery_time timestamp,foreign key(user_id) references app_user(id),foreign key(address_book_id) references address_book(id));
create table if not exists order_detail(id bigint auto_increment primary key,order_id bigint not null,name varchar(80),image varchar(500),dish_id bigint,setmeal_id bigint,dish_flavor varchar(100),number int not null,amount decimal(10,2) not null,foreign key(order_id) references orders(id) on delete cascade);
create table if not exists shop_state(id int primary key,status int not null);
